import{_ as E,C as n,o as e,c as A,a5 as r,b as s,w as t,a as l,E as i,a4 as h}from"./chunks/framework.gGRxziV4.js";const m=JSON.parse('{"title":"动态上下文与实战","description":"","frontmatter":{},"headers":[],"relativePath":"02-上下文工程/03-动态上下文与实战.md","filePath":"02-上下文工程/03-动态上下文与实战.md","lastUpdated":1774181700000}'),c={name:"02-上下文工程/03-动态上下文与实战.md"};function d(B,a,p,u,g,_){const o=n("Mermaid");return e(),A("div",null,[a[1]||(a[1]=r('<h1 id="动态上下文与实战" tabindex="-1">动态上下文与实战 <a class="header-anchor" href="#动态上下文与实战" aria-label="Permalink to &quot;动态上下文与实战&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 2 模块的第 3 章。</p></blockquote><p>从静态塞入到动态发现的转变——随着模型在充当 Agent 方面的能力不断提升，预先提供更少的细节，反而能让 Agent 更容易自主地按需提取相关上下文。</p><hr><h2 id="静态上下文-ai-的出厂设置" tabindex="-1">静态上下文：AI 的出厂设置 <a class="header-anchor" href="#静态上下文-ai-的出厂设置" aria-label="Permalink to &quot;静态上下文：AI 的出厂设置&quot;">​</a></h2><p>静态上下文是智能体启动之前准备好的——它是谁、能做什么、该怎么做。三大核心组件构成 AI 的出厂配置：</p><p><strong>系统提示</strong>是 AI 的灵魂，告诉模型身份、职责和行为方式。关键在于&quot;合适的粒度&quot;——不能太细（像伪代码一样 if-else 硬编码，模型变得死板），也不能太空（&quot;请像专家一样思考&quot;，输出飘忽不定）。结构化分层 + 迭代优化，先用最小版本测试，再针对性补充。</p><p><strong>工具</strong>是 AI 的手和眼，让 Agent 和外部世界交互。但工具定义本身也属于上下文——每个工具的名字、描述、输入输出说明都会占用模型的注意力预算。核心原则是最小可行工具集：能解决任务所需的最小那一组工具。如果人类工程师自己都不确定该用哪个工具，就别指望 AI 能选对。</p><p><strong>示例</strong>告诉模型你希望它怎么思考、怎么回答。不是训练记答案，而是教思维方式。示例太多会让上下文膨胀。好的示例不是覆盖所有情况，而是展示一种思考模式——价值不在数量而在代表性。</p><hr><h2 id="动态发现-cursor-的五大实践" tabindex="-1">动态发现：Cursor 的五大实践 <a class="header-anchor" href="#动态发现-cursor-的五大实践" aria-label="Permalink to &quot;动态发现：Cursor 的五大实践&quot;">​</a></h2><p>Cursor 团队的判断：在当下模型能力、成本和可靠性都仍受约束的阶段，最稳妥的路线是选择更简单、更可控、更可演化的原语作为外部大脑的底座。</p><h3 id="实践一-工具响应转文件" tabindex="-1">实践一：工具响应转文件 <a class="header-anchor" href="#实践一-工具响应转文件" aria-label="Permalink to &quot;实践一：工具响应转文件&quot;">​</a></h3><p>Agent 运行数据库迁移脚本，终端吐出 5000 行日志。传统做法截断到 2000 字符，关键报错可能藏在被截断的部分。Cursor 的做法：把输出完整写入文件，不塞进上下文，只告诉 Agent &quot;结果在这里&quot;。配合 Tail 工具从末尾开始探测——末尾信息够用就到此为止，不够再深入展开。先探测再展开，直到信息刚好够用。</p><h3 id="实践二-摘要时引用对话历史" tabindex="-1">实践二：摘要时引用对话历史 <a class="header-anchor" href="#实践二-摘要时引用对话历史" aria-label="Permalink to &quot;实践二：摘要时引用对话历史&quot;">​</a></h3><p>对话太长必须摘要时，原始完整对话被转存成文本文件。Agent 脑子里只有简短摘要，但手里握着历史文件的路径。发现摘要信息不够时，暂停去搜索历史文件，把具体细节精准捞回来——像开卷考试，脑子里只记重点脉络，允许随时翻书查细节。</p><h3 id="实践三-skills-按需加载" tabindex="-1">实践三：Skills 按需加载 <a class="header-anchor" href="#实践三-skills-按需加载" aria-label="Permalink to &quot;实践三：Skills 按需加载&quot;">​</a></h3><p>所有 Skill 的全文塞进 System Prompt 会造成严重膨胀。Cursor 做法：静态上下文只保留名称+描述，全文按需发现后加载。能用 Grep 关键词搜索就用关键词，关键词不够再用语义匹配。</p><h3 id="实践四-mcp-工具按需加载" tabindex="-1">实践四：MCP 工具按需加载 <a class="header-anchor" href="#实践四-mcp-工具按需加载" aria-label="Permalink to &quot;实践四：MCP 工具按需加载&quot;">​</a></h3><p>传统做法把所有工具说明书塞进 Prompt，100 个工具可能占 5 万 Token。Cursor 做法：工具说明书卸载到文件系统，初始 Prompt 只保留极简菜单。Agent 看到菜单意识到需要某个能力时，主动读取说明书文件。Token 消耗减少 46.9%。</p><h3 id="实践五-终端会话视为文件" tabindex="-1">实践五：终端会话视为文件 <a class="header-anchor" href="#实践五-终端会话视为文件" aria-label="Permalink to &quot;实践五：终端会话视为文件&quot;">​</a></h3><p>集成终端所有输出无感写入本地日志文件。用户说&quot;修好它&quot;时，Agent 不需要任何上下文，自己读取终端日志、grep 定位 error、分析堆栈、给出修复建议。整个过程不需要一次复制粘贴。</p><hr><h2 id="rag-vs-agentic-search" tabindex="-1">RAG vs Agentic Search <a class="header-anchor" href="#rag-vs-agentic-search" aria-label="Permalink to &quot;RAG vs Agentic Search&quot;">​</a></h2>',24)),(e(),s(h,null,{default:t(()=>[i(o,{id:"mermaid-68",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E9%97%AE%E9%A2%98%5D%20--%3E%20B%7BRAG%20%E8%BF%98%E6%98%AF%20Agentic%20Search%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7CRAG%3A%20%E6%8E%A8%E7%90%86%E5%89%8D%E6%A3%80%E7%B4%A2%7C%20C%5B%E9%97%AE%E9%A2%98%E5%90%91%E9%87%8F%E5%8C%96%5D%0A%20%20%20%20C%20--%3E%20D%5B%E5%90%91%E9%87%8F%E6%95%B0%E6%8D%AE%E5%BA%93%E6%9F%A5%E6%89%BE%5D%0A%20%20%20%20D%20--%3E%20E%5B%E6%8B%BC%E5%88%B0%E4%B8%8A%E4%B8%8B%E6%96%87%5D%0A%20%20%20%20E%20--%3E%20F%5B%E6%A8%A1%E5%9E%8B%E5%9B%9E%E7%AD%94%5D%0A%20%20%20%20B%20--%3E%7CAgentic%20Search%3A%20%E5%8D%B3%E6%97%B6%E6%A3%80%E7%B4%A2%7C%20G%5B%E6%A8%A1%E5%9E%8B%E6%80%9D%E8%80%83%E6%98%AF%E5%90%A6%E9%9C%80%E8%A6%81%E4%BF%A1%E6%81%AF%5D%0A%20%20%20%20G%20--%3E%20H%5B%E6%89%A7%E8%A1%8C%20list_files%5D%0A%20%20%20%20H%20--%3E%20I%5B%E8%A7%82%E5%AF%9F%E7%BB%93%E6%9E%9C%5D%0A%20%20%20%20I%20--%3E%20J%5B%E9%80%89%E6%8B%A9%E6%89%93%E5%BC%80%E6%96%87%E4%BB%B6%5D%0A%20%20%20%20J%20--%3E%20K%7B%E4%BF%A1%E6%81%AF%E5%A4%9F%E5%90%97%EF%BC%9F%7D%0A%20%20%20%20K%20--%3E%7C%E5%90%A6%7C%20L%5B%E7%BB%A7%E7%BB%AD%E6%8E%A2%E7%B4%A2%5D%0A%20%20%20%20L%20--%3E%20H%0A%20%20%20%20K%20--%3E%7C%E6%98%AF%7C%20F%0A%20%20%20%20F%20--%3E%20M%5B%E6%B7%B7%E5%90%88%E7%AD%96%E7%95%A5%E6%9C%80%E4%BC%98%5D%0A%20%20%20%20M%20--%3E%20N%5B%E5%90%AF%E5%8A%A8%E6%97%B6%20RAG%20%E9%A2%84%E5%8A%A0%E8%BD%BD%3Cbr%2F%3E%E8%BF%90%E8%A1%8C%E6%97%B6%20Agentic%20Search%20%E6%8E%A2%E7%B4%A2%5D%0A"})]),fallback:t(()=>[...a[0]||(a[0]=[l(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=r('<blockquote><p>💡 <strong>图解：</strong> RAG 是&quot;考试前发的复习提纲&quot;，Agentic Search 是&quot;开卷考试现场翻书&quot;——两者结合才是最优解。</p></blockquote><p><strong>推理前检索（RAG）</strong>：问题向量化 → 向量数据库查找相似片段 → 拼到上下文 → 交给模型。稳定、速度快、成本低，但信息可能过时、检索不够智能、无法探索。模型只能被动等待信息投喂。</p><p><strong>即时检索（Agentic Search）</strong>：模型思考是否调用工具 → 执行 list_files → 观察返回 → 选择打开 → 读取前几行 → 决定下一步。信息永远最新、只取当下需要的、具备探索能力。</p><p><strong>混合策略</strong>是最优解。Claude Code 启动时预加载 <code>CLAUDE.md</code>（RAG），运行时配备 <code>glob</code>、<code>read</code> 工具（Agentic Search）。</p><p>智能探索的两个关键机制：<strong>元数据</strong>（Agent 不仅看内容还能理解信息结构——文件名、目录、时间戳都是方向信号）和<strong>渐进式披露</strong>（不要一次塞所有信息，让模型逐步发现）。</p><hr><h2 id="行业趋势的收敛" tabindex="-1">行业趋势的收敛 <a class="header-anchor" href="#行业趋势的收敛" aria-label="Permalink to &quot;行业趋势的收敛&quot;">​</a></h2><p>Cursor、Minecraft、Devin、Anthropic 的 Skill 机制——不同团队在不同产品形态下，独立收敛到一套相似的工程思路：上下文是稀缺内存、文件系统是几乎无限的外部存储、卸载是缓解压力的基本手段、渐进式披露是默认策略。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>静态上下文三组件：系统提示（灵魂）、工具（手脚）、示例（范本）</li><li>Cursor 五大实践：响应转文件、摘要引用历史、Skills 按需加载、MCP 按需加载、终端即文件</li><li>RAG vs Agentic Search：被动投喂 vs 主动探索，混合策略最优</li><li>行业收敛：文件系统作为外部大脑是共同选择</li></ul><hr><p><strong>上一章</strong>: <a href="./02-三大支柱.html">三大支柱</a> | <strong>下一章</strong>: <a href="./04-Menlo的教训.html">Menlo的教训</a></p>',13))])}const q=E(c,[["render",d]]);export{m as __pageData,q as default};
